52: 
53:     // internal signals
54:     logic [DATA_WIDTH-1:0] core_lock_reg; 
55:     logic [DATA_WIDTH-1:0] start_reg;
56:     logic [DATA_WIDTH-1:0] length_reg;
57:     logic [DATA_WIDTH-1:0] source_addr_lsb_reg; 
58:     logic [DATA_WIDTH-1:0] source_addr_msb_reg; 
59:     logic [DATA_WIDTH-1:0] dest_addr_lsb_reg; 
60:     logic [DATA_WIDTH-1:0] dest_addr_msb_reg; 
61:     logic [DATA_WIDTH-1:0] done_reg;
62:     logic [DATA_WIDTH-1:0] end_reg;
63:     logic [DATA_WIDTH-1:0] valid;
64:     
65:     // signals from AXI 4 Lite
66:     logic [AXI_ADDR_WIDTH-1:0] address;
67: logic                      en, en_acct;
68:     logic                      we;
69:     logic [63:0] wdata;
70:     logic [63:0] rdata;
71: 
72:     // signal from reset controllger
73:     input logic rst_8;
74: 
