111:             end
112:             // We've got a write request at least one cycle earlier
113:             // wait here for the data
114:             WRITE: begin
115:                 if (axi_req_i.w_valid) begin
116:                     axi_resp_o.w_ready = 1'b1;
117:                     // use the latched address
118:                     address_o = address_q;
119:                     en_o = 1'b1;
120:                     we_o = 1'b1;

